   139→
   140→    fn event_loop(
   141→        &mut self,
   142→        terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
   143→    ) -> anyhow::Result<()> {
   144→        loop {
   145→            self.draw(terminal)?;
   146→
   147→            if event::poll(Duration::from_millis(16))?
   148→                && let Event::Key(key) = event::read()?
