   153→        }
   154→    }
   155→
   156→    fn draw(
   157→        &mut self,
   158→        terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
   159→    ) -> anyhow::Result<()> {
   160→        terminal.draw(|frame| {
   161→            let area = frame.area();
   162→            let buf = frame.buffer_mut();
   163→            self.render_all(area, buf);
