   167→
   168→    fn handle_key(&mut self, key: KeyEvent) -> bool {
   169→        match self.input_mode {
   170→            InputMode::Help => {
   171→                match key.code {
   172→                    KeyCode::Esc | KeyCode::Char('q') | KeyCode::Char('?') => {
   173→                        self.input_mode = InputMode::Normal;
   174→                    }
   175→                    _ => {}
   176→                }
   177→                return false;
   178→            }
   179→            InputMode::Filter => {
   180→                return self.handle_filter_key(key);
   181→            }
   182→            InputMode::Normal => {}
   183→        }
   184→
   185→        // Global keys
   186→        match key.code {
   187→            KeyCode::Char('q') | KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => {
   188→                return true;
   189→            }
   190→            KeyCode::Char('q') => return true,
   191→            KeyCode::Char('?') => {
   192→                self.input_mode = InputMode::Help;
   193→                return false;
   194→            }
   195→            KeyCode::Char('/') => {
   196→                self.input_mode = InputMode::Filter;
   197→                self.filter_input = Input::new(self.state.filter_text.clone());
   198→                self.filter_error = None;
   199→                return false;
   200→            }
   201→            KeyCode::Tab => {
   202→                self.focus = self.focus.next();
   203→                return false;
   204→            }
   205→            KeyCode::BackTab => {
   206→                self.focus = self.focus.prev();
   207→                return false;
   208→            }
   209→            KeyCode::Esc => {
   210→                if self.state.filter.is_some() {
   211→                    self.state.filter = None;
   212→                    self.state.filter_text.clear();
   213→                    self.state.filtered_indices = self.state.store.all_indices();
   214→                    self.event_list.selected = 0;
   215→                    self.event_list.scroll_offset = 0;
   216→                    self.state.selected_event = if self.state.filtered_indices.is_empty() {
   217→                        None
   218→                    } else {
   219→                        Some(0)
   220→                    };
   221→                }
   222→                return false;
   223→            }
   224→            _ => {}
   225→        }
   226→
   227→        // Route to focused pane
   228→        let action = match self.focus {
   229→            PaneId::EventList => self.event_list.handle_key(key, &self.state),
   230→            PaneId::DecodeTree => self.decode_tree.handle_key(key, &self.state),
   231→            PaneId::HexDump => self.hex_dump.handle_key(key, &self.state),
   232→            PaneId::Timeline => self.timeline.handle_key(key, &self.state),
   233→        };
   234→
   235→        self.process_action(action);
   236→        false
   237→    }
   238→
   239→    fn handle_filter_key(&mut self, key: KeyEvent) -> bool {
   240→        match key.code {
   241→            KeyCode::Enter => {
   242→                let text = self.filter_input.value().to_string();
   243→                if text.trim().is_empty() {
   244→                    self.state.filter = None;
   245→                    self.state.filter_text.clear();
   246→                    self.state.filtered_indices = self.state.store.all_indices();
   247→                } else {
   248→                    match Filter::parse(&text) {
   249→                        Ok(filter) => {
   250→                            self.state.filtered_indices = self.state.store.filter_indices(&filter);
   251→                            self.state.filter = Some(filter);
   252→                            self.state.filter_text = text;
   253→                            self.filter_error = None;
   254→                        }
   255→                        Err(e) => {
   256→                            self.filter_error = Some(e.to_string());
   257→                            return false;
   258→                        }
   259→                    }
   260→                }
   261→                self.event_list.selected = 0;
   262→                self.event_list.scroll_offset = 0;
   263→                self.state.selected_event = if self.state.filtered_indices.is_empty() {
   264→                    None
   265→                } else {
   266→                    Some(0)
   267→                };
   268→                self.input_mode = InputMode::Normal;
   269→                self.focus = PaneId::EventList;
   270→                false
   271→            }
   272→            KeyCode::Esc => {
   273→                self.input_mode = InputMode::Normal;
   274→                self.filter_error = None;
   275→                false
   276→            }
   277→            _ => {
   278→                self.filter_input.handle_event(&Event::Key(key));
   279→                self.filter_error = None;
   280→                false
   281→            }
   282→        }
   283→    }
   284→
   285→    fn process_action(&mut self, action: Action) {
   286→        match action {
   287→            Action::None => {}
   288→            Action::SelectEvent(idx) => {
   289→                self.state.selected_event = Some(idx);
   290→                self.hex_dump.scroll_offset = 0;
   291→                self.hex_dump.clear_highlight();
