    let mut found_protocol_indicator = false;
    for x in 0..area.width {
        let symbol = buffer[(x, last_line_y)].symbol();
        if symbol == ":" || symbol.chars().any(|c| c.is_ascii_digit()) {
            found_protocol_indicator = true;
            break;
        }
