//! Additional tests for loader.rs to improve coverage

use prb_tui::loader::{detect_format, load_events, Format};
use std::io::Write;
use tempfile::NamedTempFile;

#[test]
fn test_detect_format_json_with_content() {
    let mut temp_file = NamedTempFile::new().unwrap();
    writeln!(temp_file, r#"{{"events": []}}"#).unwrap();
    temp_file.flush().unwrap();

    let format = detect_format(temp_file.path()).unwrap();
    assert_eq!(format, Format::Json);
}

#[test]
fn test_detect_format_mcap_magic() {
    let mut temp_file = NamedTempFile::new().unwrap();
    // MCAP magic bytes
    temp_file.write_all(&[0x89, b'M', b'C', b'A', b'P', 0x30, 0x0D, 0x0A]).unwrap();
    temp_file.flush().unwrap();

    let format = detect_format(temp_file.path()).unwrap();
    assert_eq!(format, Format::Mcap);
}

#[test]
fn test_detect_format_pcap_magic() {
    let mut temp_file = NamedTempFile::new().unwrap();
    // PCAP magic number (little-endian)
    temp_file.write_all(&[0xd4, 0xc3, 0xb2, 0xa1]).unwrap();
    temp_file.flush().unwrap();

    let format = detect_format(temp_file.path()).unwrap();
    assert_eq!(format, Format::Pcap);
}

#[test]
fn test_detect_format_pcapng_magic() {
    let mut temp_file = NamedTempFile::new().unwrap();
    // PCAPng magic number
    temp_file.write_all(&[0x0a, 0x0d, 0x0d, 0x0a]).unwrap();
    temp_file.flush().unwrap();

    let format = detect_format(temp_file.path()).unwrap();
    assert_eq!(format, Format::Pcap);
}

#[test]
fn test_detect_format_empty_file() {
    let temp_file = NamedTempFile::new().unwrap();
    // Empty file should default to JSON
    let result = detect_format(temp_file.path());
    // Empty file might return an error or default - check both
    if let Ok(format) = result {
        assert_eq!(format, Format::Json);
    }
}

#[test]
fn test_detect_format_unknown_content() {
    let mut temp_file = NamedTempFile::new().unwrap();
    writeln!(temp_file, "some random content that is not a valid format").unwrap();
    temp_file.flush().unwrap();

    let format = detect_format(temp_file.path()).unwrap();
    // Should default to JSON for unknown content
    assert_eq!(format, Format::Json);
}

#[test]
fn test_load_events_nonexistent_file() {
    let result = load_events("nonexistent_file_that_does_not_exist.json");
    assert!(result.is_err(), "Should fail to load nonexistent file");
