#[test]
fn test_event_store_time_range_multiple_events() {
    let events = vec![
        make_event(1, 1_000_000_000, TransportKind::Grpc),
        make_event(2, 5_000_000_000, TransportKind::Zmq),
        make_event(3, 3_000_000_000, TransportKind::DdsRtps),
