    let mut temp_file = tempfile::Builder::new()
        .suffix(".json")
        .tempfile()
        .unwrap();
    writeln!(temp_file, r#"{{"events": []}}"#).unwrap();
    temp_file.flush().unwrap();

    let store = load_events(temp_file.path()).unwrap();
    assert_eq!(store.len(), 0);
}

