    let mut temp_file = tempfile::Builder::new()
        .suffix(".json")
        .tempfile()
        .unwrap();
    writeln!(temp_file, r#"{{ invalid json"#).unwrap();
    temp_file.flush().unwrap();

    let result = load_events(temp_file.path());
    assert!(result.is_err(), "Should fail to load malformed JSON");
}

#[test]
